// Script Continued Below
var Tasker_DocInt_API = Class.create();
Tasker_DocInt_API.prototype = {
    initialize: function() {
    },

	getStatus: function(targettablename, targettableitemid, configview){
		var status = {};
		var grDocIntLog = new GlideRecord("x_dtll2_contentint_job_log");
		grDocIntLog.addQuery('targettablename', targettablename);
		grDocIntLog.addQuery('targettableitemid', targettableitemid);
		grDocIntLog.addQuery('configview', configview);
		grDocIntLog.query();
		if(grDocIntLog.next()){
			status.value = grDocIntLog.status;
			status.displayValue = grDocIntLog.status;
			status.message = grDocIntLog.message;			
		} else {
			status.value = gs.getMessage('error');
			status.displayValue = gs.getMessage('Error');
			status.message = gs.getMessage('No Log Entry found for email');
		}
		return status;
	},
    type: 'Tasker_DocInt_API'
};
